const target = 197019074

/**
 * Time Complexity:
 *  - Generating all subarrays: O(n²)
 *  - Checking each subarray: O(n)
 *  - Total: O(n³)
 *
 * Space Complexity:
 *  - Subarray: O(n)
 *  - Frequency map: O(n)
 *  - Total: O(n)
 */
function countMajoritySubarrays(nums: number[], target: number): number {
    let count = 0;

    // generating all the sub arrays
    for (let i = 0; i < nums.length; i++) {
        const array: number[] = []
        for (let j = i; j < nums.length; j++) {
            array.push(nums[j]!)

            // if target exist increase count
            if (isMajority(array, target)) {
                count++
            }
        }
    }
    return count;
};

function isMajority(arr: number[], target: number): boolean {
    const map = new Map<number, number>();

    for (let i = 0; i < arr.length; i++) {
        map.set(arr[i]!, (map.get(arr[i]!) ?? 0) + 1)
    }
    return map.get(target)! > arr.length / 2
}

